export function getLevel(id) {
  return LEVELS.find(l => l.id === id) || null;
}

export function getLevelsInWorld(world) {
  return LEVELS.filter(l => l.world === world);
}

export const TOTAL_LEVELS = 150;
export const TOTAL_WORLDS = 10;
